import { useCallback, useRef, useState } from 'react';
import { useViewMobileLayout } from '@linm-soft-org/linm-web-common-components';
import type { CatalogListToolbarBridge, CatalogRowMenuAction } from '../components/catalog';
import { isSharedCatalogReadOnly } from '../components/catalog';
import {
  getErpListRowMenuHint,
  catalogListRowMenuHintDismissStorageKey,
} from '../utils/catalogListRowMenuHint';
import {
  getSharedCatalogEditBlockedMessage,
  catalogRowEditHintDismissStorageKey,
} from '../utils/sharedCatalogEditBlockedMessage';
import { useCatalogListPermissions } from './useCatalogListPermissions';
import type { UseCatalogListSelectionResult } from './useCatalogListSelection';

export type CatalogMasterListRowMenuRow = {
  id?: string;
  customerGroupId?: number | string;
  isReadOnly?: boolean;
};

export type UseCatalogMasterListRowMenuParams<T extends CatalogMasterListRowMenuRow> = {
  testIdPrefix: string;
  catalogKind: string;
  selection: UseCatalogListSelectionResult<T>;
  openEdit: (row: T) => void;
  openView: (row: T) => void;
  /** Create + delete only (no update API) — menu **Xem** + **Xóa**; `showEdit`/`history`/`rename` off */
  createOnlyRowMenu?: boolean;
};

export function useCatalogMasterListRowMenu<T extends CatalogMasterListRowMenuRow>({
  testIdPrefix,
  catalogKind,
  selection,
  openEdit,
  openView,
  createOnlyRowMenu = false,
}: UseCatalogMasterListRowMenuParams<T>) {
  const viewMobile = useViewMobileLayout();
  const { canWrite } = useCatalogListPermissions(catalogKind);
  const toolbarBridgeRef = useRef<CatalogListToolbarBridge | null>(null);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: T } | null>(null);
  const rowMenuHintMessage = getErpListRowMenuHint(viewMobile);

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: T; x: number; y: number }) => {
      if (createOnlyRowMenu) {
        const showView = true;
        const showDelete = canWrite;
        if (!showView && !showDelete) return;
      }
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection, createOnlyRowMenu, canWrite],
  );

  const handleRowMenuSelect = useCallback(
    (action: CatalogRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          openView(row);
          break;
        case 'edit':
          openEdit(row);
          break;
        case 'history':
          toolbarBridgeRef.current?.openHistory();
          break;
        case 'renameCode':
          toolbarBridgeRef.current?.openRename();
          break;
        case 'delete': {
          if (!selection.isRowChecked(row)) {
            selection.toggleRow(row, true);
          }
          toolbarBridgeRef.current?.openDelete();
          break;
        }
        default:
          break;
      }
    },
    [rowMenu?.row, openEdit, openView, selection],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuReadOnly = rowMenuRow ? isSharedCatalogReadOnly(rowMenuRow) : false;
  const rowMenuShowEdit = createOnlyRowMenu
    ? false
    : !!rowMenuRow && canWrite && !rowMenuReadOnly;
  const rowMenuShowView = createOnlyRowMenu
    ? !!rowMenuRow
    : !!rowMenuRow && (!canWrite || rowMenuReadOnly);
  const rowMenuShowDelete = createOnlyRowMenu
    ? !!rowMenuRow && canWrite
    : !!rowMenuRow && canWrite && !rowMenuReadOnly;

  const gridRowMenuProps = {
    getRowEditBlockedMessage: getSharedCatalogEditBlockedMessage,
    rowEditHintDismissStorageKey: catalogRowEditHintDismissStorageKey(testIdPrefix),
    onRowOpenActionMenu: handleRowOpenActionMenu,
    rowMenuHintMessage,
    rowMenuHintDismissStorageKey: catalogListRowMenuHintDismissStorageKey(testIdPrefix),
    enableRowMenuLongPress: viewMobile,
  };

  const rowActionMenuProps = {
    open: rowMenu != null,
    x: rowMenu?.x ?? 0,
    y: rowMenu?.y ?? 0,
    onClose: () => setRowMenu(null),
    onSelect: handleRowMenuSelect,
    testIdPrefix,
    showEdit: rowMenuShowEdit,
    showView: rowMenuShowView,
    showHistory: createOnlyRowMenu ? false : !!rowMenuRow,
    showRename: rowMenuShowEdit,
    showDelete: rowMenuShowDelete,
  };

  return {
    canWrite,
    toolbarBridgeRef,
    gridRowMenuProps,
    rowActionMenuProps,
    openEditWithPerm: useCallback(
      (row: T) => {
        if (!canWrite || isSharedCatalogReadOnly(row)) {
          openView(row);
          return;
        }
        openEdit(row);
      },
      [canWrite, openEdit, openView],
    ),
  };
}
